10fabcc7  			payload.chat_template_kwargs = {
8bbe574c  				...(payload.chat_template_kwargs ?? {}),
2ab016ff  				...variantSnapshot.harness.chat_template_kwargs,
ea5ef463  			};
3713bbfd  		}
32425a3c  		// Note: variant-specific system prompt mutation is deferred to the
d9b87aab  		// @emmy/ux caller; pi-emmy-extension.ts's before_provider_request
850a3820  		// handler rebuilds assembledPrompt.text when harness.prompts.system
a1777d96  		// points at a variant-specific file. This hook only applies the
fcf1228c  		// chat-request-shape fields directly.
a32a3bb7  	}
e3b0c442  
3d9fbe13  	// (b) D-02b: reactive grammar injection (Phase 2 D-11 live-path wiring).
421e8d5e  	if (retryState?.wantsGrammar === true) {
31c64a28  		const grammarCfg = profile.harness.tools.grammar;
725e668b  		if (grammarCfg !== null && grammarCfg.mode !== "disabled") {
16d8a3c9  			const grammarText = readFileSync(
85fd2760  				join(profile.ref.path, grammarCfg.path),
6a45000e  				"utf8",
cdf704fc  			);
9c960f81  			payload.extra_body = {
5ea79770  				...(payload.extra_body ?? {}),
cec6e89c  				guided_decoding: { grammar_str: grammarText },
ea5ef463  			};
3713bbfd  		}
a32a3bb7  	}
e3b0c442  
dc480f40  	// (c) D-02c + D-04: replace the system message with emmy's 3-layer prompt.
226a6259  	const idx = payload.messages.findIndex((m) => m.role === "system");
